---@class LGiftRoleBubble
local LGiftRoleBubble = LxClass("LGiftRoleBubble", LBubbleBase)
local typeOfTextMesh = typeof(CS.TextMeshPro)
local BuildingClick = CS.BuildingClick
local Tweening = DG.Tweening


function LGiftRoleBubble:LGiftRoleBubble()
    self._seqCom = SequenceCom:New()
end

function LGiftRoleBubble:GetPrefabPath()
    return "UI/Prefabs/Com/GiftRoleBubble","UI/Prefabs/Com","GiftRoleBubble"
end

function LGiftRoleBubble:OnSetBubbleContent(item,itemdata)
    self:SetFollow(itemdata.followTran,itemdata.offset)
    local img = CS.FindTrans(item,"bubble")
    local comp = BuildingClick.Get(img.gameObject)
    if comp then
        comp.ClickDelegate = itemdata.callBack
    end

    local seq = self._seqCom:CreateSeq("scale")
    item.localScale = Vector3.one
    local tween = item:DOScale(Vector3.one*0.9,1)
    seq:Append(tween)
    seq:SetLoops(-1,Tweening.LoopType.Yoyo)
    seq:PlayForward()
end


return LGiftRoleBubble